function validateRequired(){
  clearFieldErrors();
  const required=[
    ['registration','Matrícula'],['flightDate','Fecha'],['departure','Salida'],
    ['departureTime','Hora UTC'],['destination','Destino'],['eet','EET total']
  ];

  for(const [id,label] of required){
    const element=$(id);
    const value=String(element?.value || '').trim();
    if(!value){
      element?.classList.add('field-error');
      element?.scrollIntoView({behavior:'smooth',block:'center'});
      setTimeout(()=>element?.focus(),250);
      throw new Error(`Falta diligenciar el campo: ${label}. El texto gris de ejemplo no cuenta como dato.`);
    }
  }
}

async function makePdfFile(){
  // En iPhone, cerrar el teclado antes de leer el campo evita que quede pendiente
  // el último texto escrito.
  if(document.activeElement && typeof document.activeElement.blur==='function'){
    document.activeElement.blur();
  }
  await new Promise(resolve=>requestAnimationFrame(()=>requestAnimationFrame(resolve)));
  validateRequired();
  if(!validateItem18All()){
    $('item18OverallStatus')?.scrollIntoView({behavior:'smooth',block:'center'});
    throw new Error('La casilla 18 tiene errores. GutiPilot los marcó en rojo y explica cómo corregirlos.');
  }
  const doc=await createPdf();
  const blob=doc.output('blob');
  return {doc, blob, file:new File([blob],filename(),{type:'application/pdf'})};
}
async function sharePdfFile(file,title,text=''){
  if(navigator.canShare && navigator.canShare({files:[file]})){
    await navigator.share({files:[file],title,text});
    return true;
  }
  return false;
}
function forceDownload(blob,name){
  const url=URL.createObjectURL(blob), a=document.createElement('a');
  a.href=url;a.download=name;document.body.appendChild(a);a.click();a.remove();
  setTimeout(()=>URL.revokeObjectURL(url),5000);
}
